INSERT INTO `products` VALUES (1,'Mobiles','Experience cutting-edge technology with the Apple iPhone, designed to deliver exceptional performance, premium design, and advanced features. The device features a sleek and durable build, a high-resolution display for stunning visuals, and powerful processing capabilities for smooth multitasking and gaming.\nEquipped with an advanced camera system, it allows you to capture high-quality photos and videos even in low-light conditions. ',20,'https://m.media-amazon.com/images/I/616-Eh2FbPL._AC_UY218_.jpg','Apple iPhone',90000.00,6,'IPH-APL-001',97),(2,'Audio','Upgrade your audio experience with the Vaku Luxos® SONAIR TWS Bluetooth 5.4 Earbuds, designed for seamless connectivity, superior sound quality, and long-lasting performance. Featuring the latest Bluetooth 5.4 technology, these earbuds ensure stable connections, low latency, and efficient power usage for an enhanced listening experience.',25,'https://m.media-amazon.com/images/I/71svoDNUgIL._AC_UL320_.jpg','Vaku Luxos',2000.00,6,'VAK-SONAIR-TWS-001',30),(3,'Fashion','Stay stylish and comfortable with this Women Oversized Cotton Jersey T-Shirt, designed for a relaxed and trendy streetwear look. Made from soft and breathable cotton jersey fabric, this t-shirt ensures all-day comfort, making it perfect for casual outings, lounging, or everyday wear.\nThe oversized loose fit provides a modern silhouette, offering both comfort and effortless style. Its versatile design pairs easily with jeans, shorts, joggers, or skirts, making it a must-have wardrobe essential. Whether you\'re going for a chic street style or a laid-back vibe, this t-shirt adapts to your fashion needs.',24,'https://m.media-amazon.com/images/I/51L4BRS2h1L._AC_UL320_.jpg',' Cotton Jersey T-Shirt ',890.00,6,'WOM-TSH-OVR-001',23),(4,'Audio','Experience clear and immersive sound with these Nintendo Classic Wired Earphones. Designed in a sleek white finish with iconic Nintendo-inspired styling, these earphones offer comfortable in-ear fit and high-quality audio performance. Perfect for gaming,...',12,'https://cdn.shopify.com/s/files/1/0586/3270/0077/files/0000s_0028_Ear-_open_-white.png?v=1753759514','Wired Earphones ',3999.00,6,'EAR-NIN-001',23),(5,'Beauty','Olay Regenerist Retinol 24 Night Cream is an advanced overnight moisturizer that renews and resurfaces the skin while you sleep. It is formulated with a powerful combination of Retinol and Vitamin B3 (Niacinamide) to improve skin texture, reduce fine lines and wrinkles, and enhance overall radiance.',14,'https://m.media-amazon.com/images/I/61bfztozHgL._AC_UL320_.jpg','Olay Regenerist Retinol',1690.00,6,'OL-R24-NC-50G',23),(6,'Beauty','Lakme Xtraordin-airy Matte Real Mousse Foundation is a lightweight, airy mousse foundation that delivers a smooth matte finish for a flawless look. Its unique whipped formula blends effortlessly into the skin, providing even coverage while minimizing the appearance of pores.\nEnriched with SPF 8, it offers basic sun protection while keeping your skin fresh and shine-free throughout the day. ',5,'https://m.media-amazon.com/images/I/41yTVMm1DoL._AC_UL320_.jpg',' Lakme Xtraordin-airy ',345.00,6,' LK-XAMM-05-BH-25G',19),(7,'Beauty','Beauty of Joseon Relief Sun Aqua-Fresh Rice + B5 Sunscreen is a lightweight, hydrating sun cream designed to provide strong sun protection while keeping the skin moisturized and calm. Formulated with rice extract and Vitamin B5 (Panthenol), it helps nourish the skin, improve moisture retention, and soothe irritation.\nWith SPF 50+ PA++++, it offers high-level protection against harmful UVA and UVB rays. The aqua-fresh texture absorbs quickly without leaving a white cast or greasy residue, making it ideal for daily use. ',20,'https://m.media-amazon.com/images/I/518ZII9nOxL._AC_UL320_.jpg','Relief Sun Aqua-Fresh',2365.00,6,' BOJ-RS-AF-50SPF',54),(8,'Home','Showstopper Microfiber Cleaning Cloth is a versatile set of high-quality cleaning wipes designed for efficient and streak-free cleaning. Made from ultra-soft microfiber material, these cloths effectively trap dust, dirt, and moisture without scratching surfaces.\nPerfect for kitchen use as well as general home cleaning, these cloths can be used for dusting, wiping, and polishing a variety of surfaces including countertops, glass, appliances, and furniture. They are highly absorbent, reusable, and durable, making them an eco-friendly and cost-effective cleaning solution.',24,'https://m.media-amazon.com/images/I/51iN4ZXIBhL._AC_UL320_.jpg','Showstopper Microfiber ',564.00,6,' SS-MC-12PK',23),(9,'Fitness','Dr Trust USA 526 Legend BMI Weight Scale & Body Fat Analyzer is a smart digital weighing scale designed to provide comprehensive body measurements beyond just weight. It accurately analyzes key health indicators such as Body Fat, BMI, Muscle Mass, Bone Mass, and more, helping you track your overall fitness progress.\nThis smart scale easily syncs with iOS and Android apps, allowing you to monitor and store your health data in real time.',13,'https://m.media-amazon.com/images/I/71NTdqTLhlL._AC_UL320_.jpg','Body Fat Analyzer',2300.00,6,'DT-526-BMI-SCALE',23),(10,'Home','Amazon Basics Artificial Plants with Pot are realistic-looking decorative plants designed to enhance the beauty of your indoor spaces without the need for maintenance. Made from durable, high-quality plastic, these plants feature lifelike details and a natural appearance that adds a refreshing touch to any room.\nThis multi-variety set is perfect for decorating living rooms, bedrooms, offices, or kitchens. Each plant comes in a stylish pot, making it ready to place anywhere for instant decor.',32,'https://m.media-amazon.com/images/I/710jjgj13jL._AC_UL320_.jpg','Artificial Plants with Pot',1234.00,6,' AB-AP-MV-DECOR',20),(11,'Home','PNB Kitchenmate Triply Stainless Steel Frying Pan is a premium quality cookware designed for efficient and healthy cooking. Made with triply construction, it features three layers—stainless steel, an aluminum core, and stainless steel—ensuring even heat distribution and faster cooking.\nThe 20 cm frying pan comes with a sturdy lid, making it perfect for frying, sautéing, and everyday cooking. ',45,'https://m.media-amazon.com/images/I/71DBUwVdOSL._AC_UL320_.jpg','Steel Frying Pan ',2076.00,6,'PNB-KM-TP-FP20',54),(12,'Fitness','FASHNEX Resistance Bands are versatile and durable exercise bands designed to support a wide range of workouts, from strength training to mobility and stretching exercises. These pull-up assist bands help beginners and professionals improve their performance by providing the right level of resistance and support.\nMade from high-quality, stretchable material, these bands are ideal for home workouts, gym sessions, and rehabilitation exercises. ',21,'https://m.media-amazon.com/images/I/81exiSOZc4L._AC_UL320_.jpg',' Pull Up Exercise Band',3456.00,6,' FX-RB-PULLUP',21),(13,'Fitness','Spike Tummy Trimmer Yoga Pedal Puller is a versatile resistance band designed for effective full-body workouts at home. It is ideal for targeting the abdomen, legs, arms, and core muscles, helping you build strength, improve flexibility, and maintain overall fitness.\nEquipped with durable elastic resistance bands, comfortable foot pedals, and easy-grip handles, this fitness tool allows you to perform various exercises such as tummy trimming, stretching, toning, and strength training. It is suitable for both men and women and can be used for yoga, pilates, and general home workouts.',10,'https://m.media-amazon.com/images/I/61DTbNQQZjL._AC_UL320_.jpg',' Yoga Pedal Puller',1267.00,6,' SP-TT-YPP-RES',12),(14,'Audio','EMEET M1A USB Speakerphone is a high-performance computer speaker with built-in AI-powered microphones designed for clear and professional communication. Featuring 360° voice pickup, it ensures that voices are captured from all directions, making it perfect for meetings, conference calls, and online collaboration.\nThis Zoom-certified speakerphone delivers enhanced audio clarity with intelligent noise reduction, allowing for smooth and uninterrupted conversations. ',20,'https://m.media-amazon.com/images/I/81kjKi4Sv7L._AC_UY218_.jpg','M1A USB Speakerphone',5426.00,6,'EM-M1A-SPK',21),(15,'Fashion','This elegant 925 Silver Golden Glint Pendant with Link Chain is a beautifully crafted piece designed to add a touch of sophistication to any outfit. Made from high-quality 925 sterling silver with a golden finish, this pendant offers a perfect blend of durability and style.\nThe delicate design makes it suitable for both everyday wear and special occasions, making it an ideal gift for women and girls. It comes with a matching link chain that complements the pendant perfectly, creating a complete and stylish jewelry set.',43,'https://m.media-amazon.com/images/I/51SvnNKVyVL._AC_UL320_.jpg','925 Silver Golden Glint',9990.00,6,'SG-925-PENDANT-GLINT',43),(16,'Fashion','Premium Analogue Women\'s Rose Gold Magnet Watch is a stylish and elegant timepiece designed to enhance your everyday look. Featuring a sleek rose gold dial and a matching magnetic bracelet strap, this watch offers both sophistication and comfort.\nThe magnetic strap ensures a secure and adjustable fit without the need for clasps, making it easy to wear and remove. ',17,'https://m.media-amazon.com/images/I/71nbOk-3qUL._AC_UL320_.jpg','Gold Magnet Watch ',457.00,6,'RG-MAG-WATCH-W',87),(17,'Mobiles','Apple iPhone 17 Pro Max 2TB is a top-of-the-line flagship smartphone designed for ultimate performance and premium user experience. It features a large 6.9-inch (17.42 cm) ProMotion display that delivers smooth scrolling, vibrant colors, and sharp visuals for an immersive viewing experience.\nPowered by the advanced A19 Pro chip, the device ensures ultra-fast performance, seamless multitasking, and excellent efficiency for gaming, content creation, and everyday use. ',5,'https://m.media-amazon.com/images/I/71MXmswILHL._AC_UY218_.jpg','Apple iPhone 17 Pro Max',99999.00,6,'APP-IP17PM-2TB',23),(18,'Mobiles','OnePlus 15R is a high-performance smartphone designed for speed, power, and next-level user experience. Equipped with 12GB RAM and 512GB storage, it ensures seamless multitasking and ample space for apps, games, photos, and videos.\nPowered by the world’s first Snapdragon® 8 Gen 5 processor, this device delivers exceptional speed, efficiency, and gaming performance. The massive 7400mAh battery provides long-lasting usage, allowing you to stay connected, entertained, and productive throughout the day without frequent charging.',13,'https://m.media-amazon.com/images/I/61AsNTuJ6mL._AC_UY218_.jpg','OnePlus 15R 12GB RAM ',89000.00,6,'OP-15R-12GB-512GB-CB',32),(19,'Mobiles','OnePlus Nord CE6 is a powerful and feature-packed smartphone built for smooth performance and long-lasting usage. Equipped with 8GB RAM and 128GB storage, it ensures efficient multitasking and sufficient space for everyday apps, photos, and media.\nPowered by the Snapdragon 7s Gen 4 processor, the device delivers reliable speed and responsiveness for daily tasks, gaming, and entertainment. It features a massive 8000mAh battery, providing extended usage time so you can stay connected without frequent charging.',20,'https://m.media-amazon.com/images/I/61Di24QT6GL._AC_UL320_.jpg',' OnePlus Nord CE6 8GB ',55000.00,7,'OP-NCE6-8GB-128GB-PB',30),(20,'Mobiles','realme NARZO 80 Pro 5G is a powerful smartphone designed for high performance, speed, and long-lasting usage. Equipped with 12GB RAM and 256GB storage, it ensures seamless multitasking and ample space for apps, games, photos, and videos.\nPowered by the segment’s first MediaTek Dimensity 7400 chipset, the device delivers fast processing, smooth gaming, and efficient performance. It comes with a massive 6000mAh Titan Battery that provides extended usage throughout the day, paired with 80W ultra-fast charging for quick power-ups.',10,'https://m.media-amazon.com/images/I/71J+dpjrzhL._AC_UY218_.jpg',' realme NARZO 80 Pro',46000.00,7,'RM-NARZO80P-12GB',31),(21,'Mobiles','realme NARZO 90 5G is a high-performance smartphone designed for power, speed, and advanced camera capabilities. Equipped with 8GB RAM and 128GB storage, it ensures smooth multitasking and sufficient space for apps, media, and files.\nThe device features a massive 7000mAh battery, offering one of the longest battery lives in its segment, ensuring all-day usage without interruptions. With 60W fast charging, you can quickly recharge and get back to your activities in no time.',29,'https://m.media-amazon.com/images/I/81c-THT67CL._AC_UY218_.jpg','realme NARZO 90 5G 8GB',30000.00,7,'RM-NARZO90-8GB-128GB',44),(22,'Audio','ACwO DwOTS Muze Bluetooth Earbuds are advanced wireless earbuds designed for a premium audio experience with multiple smart features. Equipped with an in-built MP3 player and TF card support, these earbuds allow you to enjoy music directly without needing a smartphone.\nFeaturing 10mm audio drivers, the earbuds deliver clear sound quality with deep bass and balanced audio. The recording mode and real-time audio monitoring make them ideal for users who want added functionality for voice capture and listening control.',13,'https://m.media-amazon.com/images/I/713HmsaSdXL._AC_UY218_.jpg','Muze Bluetooth Earbuds ',4300.00,7,'AC-MUZE-BT-EB',32),(23,'Audio','Saregama Carvaan Mini 2.0 Telugu is a compact and portable music player designed for lovers of classic Telugu songs. Pre-loaded with a wide collection of evergreen tracks, it allows you to enjoy music anytime without the need for internet connectivity.\nThis device supports multiple listening options including Bluetooth, FM/AM radio, and AUX connectivity, giving you flexibility to play music from various sources. The built-in speaker delivers clear and rich sound, making it perfect for personal listening or small gatherings.',21,'https://m.media-amazon.com/images/I/81jdlxGggkL._AC_UL320_.jpg','Music Player Sunset Red',3698.00,7,'SG-CARVAAN-MINI2-TEL',21),(24,'Audio','Audio Array AI-04 HD 2x2 Gen 3 Audio Interface is a professional-grade recording device designed for musicians, podcasters, and content creators who demand high-quality sound. It features premium microphone preamps that deliver clear, low-noise audio capture, making it ideal for studio-quality recordings.\nEquipped with 48V phantom power, this interface supports condenser microphones, ensuring versatility for vocals, instruments, and voice-over work. With support for 24-bit/192kHz high-resolution audio, it provides detailed and accurate sound reproduction for professional results.',29,'https://m.media-amazon.com/images/I/51W18VdbcsL._AC_UY218_.jpg','Audio Array AI-04 HD',6789.00,7,'AA-AI04-HD-G3',18),(25,'Fashion','Women’s Rayon Printed Anarkali Kurta and Pant with Dupatta Set is a stylish and comfortable ethnic outfit designed for everyday elegance and special occasions. Made from soft and breathable rayon fabric, this set ensures all-day comfort while giving a graceful and flattering look.\nThe Anarkali-style kurta features beautiful prints that enhance its traditional appeal, paired with matching pants for a complete outfit. The set also includes a coordinated dupatta that adds a touch of sophistication and completes the overall look.',40,'https://m.media-amazon.com/images/I/51JtGs04X7L._AC_UL320_.jpg','Printed Anarkali Kurta',1236.00,7,' WR-ANRK-SET-PRINT',9),(26,'Fashion','Men’s Stylish Cotton Blend Casual Shirt is designed for comfort and modern style, making it a perfect addition to your everyday wardrobe. Crafted from a soft and breathable cotton blend fabric, this shirt ensures all-day comfort while maintaining a smart and polished look.\nFeaturing a full sleeve design with a classic button-down front, it offers a versatile style suitable for both casual outings and semi-formal occasions. The well-tailored fit enhances your appearance, while the lightweight fabric keeps you comfortable throughout the day.',56,'https://m.media-amazon.com/images/I/6114oJ6wgoL._AC_UL320_.jpg','Cotton Blend Casual Shirt',890.00,7,' MS-CB-CASUAL-FS',34),(27,'Fashion','Baggy Hip-Hop Graphic Printed T-Shirt for Men is a trendy and stylish oversized t-shirt designed for a bold streetwear look. Made from soft and breathable fabric, it ensures all-day comfort with a relaxed and loose fit.\nFeaturing eye-catching graphic prints inspired by hip-hop culture, this t-shirt adds a modern and edgy touch to your outfit. The oversized design provides freedom of movement and a laid-back vibe, making it perfect for casual outings, streetwear fashion, and everyday wear.',20,'https://m.media-amazon.com/images/I/51kJ2ga3xUL._AC_UL320_.jpg','T-Shirt for Men Oversized',890.00,7,' MH-BAGGY-GRAPHIC-TS',30),(28,'Beauty','Forest Essentials Light Day Lotion Madurai Jasmine & Mogra is a luxurious Ayurvedic moisturizer designed to hydrate, protect, and nourish the skin throughout the day. Enriched with natural ingredients and the soothing essence of jasmine and mogra, it helps keep the skin soft, refreshed, and radiant.\nFormulated with SPF 30 PA++, this lightweight lotion provides effective protection against harmful UVA and UVB rays while maintaining skin moisture balance. Its non-greasy texture absorbs quickly, making it ideal for daily use under makeup or on its own.',12,'https://m.media-amazon.com/images/I/6102W8nVyqL._AC_UL320_.jpg',' Lotion Madurai Jasmine ',4390.00,7,'FE-LDL-JM-SPF30',26),(29,'Beauty','L\'Oréal Professionnel Paris Liss Unlimited Hair Mask is an intensive smoothing treatment specially designed for frizzy and unruly hair. Enriched with nourishing ingredients, it deeply conditions the hair, leaving it soft, smooth, and more manageable.\nThis professional formula helps control frizz and humidity, providing long-lasting smoothness and shine. It works by strengthening the hair fiber and improving texture, making styling easier while reducing dryness and roughness.',19,'https://m.media-amazon.com/images/I/61bxrH0it0L._AC_UL320_.jpg','Liss Unlimited Hair Mask',3499.00,7,'LP-LISS-MASK-200',32),(30,'Beauty','HYUE Velvette Kiss Gift Set In Berries is a luxurious lip color collection designed to deliver a rich, velvety matte finish with long-lasting wear. This set features beautiful berry shades that enhance your look with bold, vibrant color while maintaining a soft, lightweight feel on the lips.\nFormulated with nourishing ingredients like Jojoba, it helps keep lips smooth, hydrated, and comfortable throughout the day without drying them out. The feather-light powder matte texture glides effortlessly for even application and a flawless finish.',21,'https://m.media-amazon.com/images/I/71benpYBzOL._AC_UL320_.jpg','Gift Set In Berries',5400.00,7,'HY-VK-GS-BER',23),(31,'Home','Chitshakti Emerald Crystal Tree is a beautifully handcrafted gemstone tree designed to bring positivity, prosperity, and harmony into your living space. Made with 500 emerald-colored crystal beads, this decorative piece symbolizes growth, success, and abundance according to Feng Shui principles.\nThe tree is carefully arranged to resemble a natural bonsai, making it an elegant showpiece for homes, offices, or workspaces. Known for its calming and healing energy, the emerald crystal is believed to attract good fortune while promoting balance and emotional well-being.',13,'https://m.media-amazon.com/images/I/71JGiJo6J5L._AC_UL320_.jpg','Chitshakti Crystal Tree',3461.00,7,' CS-ECT-500',21),(32,'Home','100% Pure Brass Kalpavriksha Tree with Birds is a beautifully crafted decorative showpiece that represents the Tree of Life, symbolizing growth, prosperity, and positive energy. Made from high-quality pure brass, this elegant piece features intricate detailing of branches and birds, adding a traditional and artistic touch to your space.\nInspired by Vastu and Feng Shui principles, the Kalpavriksha tree is believed to bring good luck, harmony, and abundance into homes and offices. Its compact 6-inch size makes it ideal for placing on tables, shelves, or पूजा spaces, enhancing both aesthetic appeal and spiritual ambiance.',13,'https://m.media-amazon.com/images/I/819vg0XRfiL._AC_UL320_.jpg','Pure Kalpavriksha Tree',2340.00,7,'BK-KT-6IN',34),(33,'Home','Deejay Kitchen Shelf Wall Mount Multipurpose Holder is a practical and space-saving storage solution designed to keep your kitchen organized and clutter-free. Made from high-grade metal, this durable rack is perfect for holding knives, kitchen tools, and everyday essentials in one convenient place.\nIt features multiple sections including a knife holder, towel hanger, and hooks for hanging spatulas, ladles, and other utensils. The sturdy wall-mount design helps maximize kitchen space while keeping everything easily accessible.',21,'https://m.media-amazon.com/images/I/71CnHSNe83L._AC_UL320_.jpg','Kitchen Shelf Wall Mount',4590.00,7,'DJ-KS-WM-MULTI',29),(34,'Fitness','Boldfit Abs Roller is a premium workout tool designed to strengthen and tone your core muscles effectively. Suitable for both men and women, this ab wheel helps target the abdomen, shoulders, arms, and back, making it ideal for full-body strength training at home or in the gym.\nBuilt with high-quality materials, the roller provides stability, durability, and smooth performance during workouts. Its ergonomic handles offer a firm and comfortable grip, allowing better control and reduced strain on the hands.',11,'https://m.media-amazon.com/images/I/71fZgNr+KuL._AC_UL320_.jpg','Boldfit Abs Roller for Men',987.00,7,'BF-ABS-ROLLER',11),(35,'Fitness','SPIKE Ab Exercise Double Suction Cup Sit-Up Bar is a compact and effective workout tool designed to help strengthen your core and improve overall fitness. This adjustable sit-up bar easily attaches to flat surfaces using powerful double suction cups, providing strong stability during exercise.\nIt is ideal for performing sit-ups, crunches, leg workouts, and arm exercises, helping you target abdominal, leg, and upper body muscles efficiently. The adjustable height feature ensures a comfortable fit for different users, making it suitable for both beginners and fitness enthusiasts.',34,'https://m.media-amazon.com/images/I/614wvhZGr-L._AC_UL320_.jpg','Cup Sit-Up Bar',5432.00,7,'SP-ABS-SUCTION',5),(37,'Fitness','The SPARNOD FITNESS SMB-100 Mini Cycle Pedal Exerciser is a compact and convenient solution for light exercise at home or office. Designed for both upper and lower body workouts, this mini cycle helps improve circulation, muscle strength, and joint mobility. It comes with adjustable resistance to suit different fitness levels and a secure fixing strap for stable use. The built-in digital display tracks essential workout data such as time, distance, calories burned, and pedal count, helping you stay motivated and monitor your progress. Ideal for beginners, seniors, and rehabilitation exercises, its lightweight and portable design makes it easy to use anytime, anywhere.\n',45,'https://m.media-amazon.com/images/I/613nOKkeBiL._AC_UL320_.jpg',' Mini Cycle Pedal',2999.00,7,'SMB-100-MN',29);
